import json
from collections import Counter
from flask import Flask, request, jsonify
from sklearn.ensemble import RandomForestClassifier

app = Flask(__name__)

# Define the REST API endpoints
@app.route('/label', methods=['POST'])
def label():
    # Get the image data and labels from the request body
    image_data = request.get_json()['image']
    labels = request.get_json()['labels']

    # Validate the input data
    if not isinstance(image_data, bytes) or not isinstance(labels, list):
        return jsonify({'error': 'Invalid input data'}), 400

    # Aggregate the labels using majority voting
    label_counts = Counter(labels)
    most_frequent_label = label_counts.most_common()[0][0]

    # Train a random forest classifier on the labeled data
    clf = RandomForestClassifier(n_estimators=10, random_state=42)
    clf.fit(image_data, labels)

    # Make predictions on new images using the trained model
    def predict(new_image):
        return clf.predict(new_image)[0]

    # Return the predicted label and the confidence score
    return jsonify({'label': most_frequent_label, 'confidence': clf.score(new_image)})

if __name__ == '__main__':
    app.run(debug=True)